import{c as n}from"./app.8935f5f1.js";const s={},a=n('<h3 id="oracle-12541-12560-00511无监听程序-协议适配器错误问题分析及解决方案" tabindex="-1"><a class="header-anchor" href="#oracle-12541-12560-00511无监听程序-协议适配器错误问题分析及解决方案" aria-hidden="true">#</a> oracle 12541，12560，00511无监听程序， 协议适配器错误问题分析及解决方案</h3><ul><li>连接不上</li></ul><p>问题描述：</p><ol><li><code>lsnrctl start、stop、</code>非常慢，出现卡顿现象；</li><li>执行lsnrctl详细情况如下</li></ol><div class="language-bash ext-sh"><pre class="language-bash"><code>C:UsersAdministrator<span class="token operator">&gt;</span> lsnrctl stop\nLSNRCTL <span class="token keyword">for</span> <span class="token number">64</span>-bit Windows: Version <span class="token number">11.2</span>.0.1.0 - Production on <span class="token number">17</span>-8月 -2015 <span class="token number">17</span>:24:28\nCopyright <span class="token punctuation">(</span>c<span class="token punctuation">)</span> <span class="token number">1991</span>, <span class="token number">2010</span>, Oracle.  All rights reserved.\n正在连接到 <span class="token punctuation">(</span>DESCRIPTION<span class="token operator">=</span><span class="token punctuation">(</span>ADDRESS<span class="token operator">=</span><span class="token punctuation">(</span>PROTOCOL<span class="token operator">=</span>TCP<span class="token punctuation">)</span><span class="token punctuation">(</span>HOST<span class="token operator">=</span>【计算机名】<span class="token punctuation">)</span><span class="token punctuation">(</span>PORT<span class="token operator">=</span><span class="token number">1521</span><span class="token punctuation">)</span>\n<span class="token punctuation">))</span>\nTNS-12541: TNS: 无监听程序\nTNS-12560: TNS: 协议适配器错误\n  TNS-00511: 无监听程序\n   <span class="token number">64</span>-bit Windows Error: <span class="token number">61</span>: Unknown error\n正在连接到 <span class="token punctuation">(</span>DESCRIPTION<span class="token operator">=</span><span class="token punctuation">(</span>ADDRESS<span class="token operator">=</span><span class="token punctuation">(</span>PROTOCOL<span class="token operator">=</span>IPC<span class="token punctuation">)</span><span class="token punctuation">(</span>KEY<span class="token operator">=</span>EXTPROC1521<span class="token punctuation">))</span><span class="token punctuation">)</span>\nTNS-12541: TNS: 无监听程序\nTNS-12560: TNS: 协议适配器错误\n  TNS-00511: 无监听程序\n   <span class="token number">64</span>-bit Windows Error: <span class="token number">2</span>: No such <span class="token function">file</span> or directory\n</code></pre></div><p>原因分析：</p><ol><li>oracle服务器长时间运转，监听日志listener.log日志超过2G（或4G），造成监听程序无法启动</li><li>oracle的bug所致：<strong>Oracle一个BUG，BUG号为9879101</strong> : <code>THE CONNECT THROUGH LISTENER WAS SLOW WHEN LISTNER LOG GROWED 4GB</code></li></ol><p>解决方案： 清理<strong>listener.log</strong>日志 监听日志所在目录：<strong>E:appAdministratordiag nslsnr【计算机名】listener racelistener.log；【超过4G，可直接删除】</strong> 直接删除此监听日志，重启监听程序即可。</p><p>参考文章： <code>http://www.luocs.com/archives/464.html</code></p>',9);s.render=function(n,s){return a};export{s as default};
